// Code in JavaScript — revision path
// Receives Send message and wait for response → Get a row

const proposal = $input.first().json;
const trigger = $('Telegram Trigger').first().json;

const from =
  trigger.callback_query?.from ||
  trigger.message?.from ||
  trigger.edited_message?.from ||
  null;

const userId = from?.id || null;

if (!userId) {
  throw new Error('Cannot identify user — Telegram from.id missing');
}

const username = from
  ? (`${from.first_name || ''} ${from.last_name || ''}`).trim() || from.username || 'Unknown'
  : 'Unknown';

const revisionText = trigger.message?.text || trigger.edited_message?.text || '';

return [{ json: {
  user_message:           revisionText,
  user_id:                userId,
  username:               username,
  structured_contact_data: null,
  previous_proposal: {
    action:  proposal.action,
    module:  proposal.module,
    fields:  proposal.fields,
    step_queue: proposal.step_queue || null
  },
  last_execution_result:  null,
  is_reset:               false
}}];

